import{_ as d,o as a,c as n,a3 as s}from"./chunks/framework.CVjg771q.js";const b=JSON.parse('{"title":"天干地支","description":"甲子乙丑丙寅丁卯——中国纪年纪月纪日纪时的底层编码系统。","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"天干地支","description":"甲子乙丑丙寅丁卯——中国纪年纪月纪日纪时的底层编码系统。"},"headers":[],"relativePath":"changshi/tiangan-dizhi/index.md","filePath":"changshi/tiangan-dizhi/index.md","lastUpdated":1779783531000}'),e={name:"changshi/tiangan-dizhi/index.md"};function r(i,t,l,p,h,o){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="天干地支" tabindex="-1">天干地支 <a class="header-anchor" href="#天干地支" aria-label="Permalink to &quot;天干地支&quot;">​</a></h1><blockquote><p>「干」如树干，为主；「支」如枝条，为辅。两者相配，循环运转。 起源可追溯至殷商时代（约公元前14世纪），是中华文明最古老的计时体系之一。</p></blockquote><h2 id="天干-·-十个符号" tabindex="-1">天干 · 十个符号 <a class="header-anchor" href="#天干-·-十个符号" aria-label="Permalink to &quot;天干 · 十个符号&quot;">​</a></h2><p>天干共 <strong>10个</strong>，按顺序排列。奇数位为阳干，偶数位为阴干；五行各占两位，阴阳各半。</p><table tabindex="0"><thead><tr><th>序号</th><th>天干</th><th>五行</th><th>阴阳</th></tr></thead><tbody><tr><td>1</td><td>甲</td><td>木</td><td>阳</td></tr><tr><td>2</td><td>乙</td><td>木</td><td>阴</td></tr><tr><td>3</td><td>丙</td><td>火</td><td>阳</td></tr><tr><td>4</td><td>丁</td><td>火</td><td>阴</td></tr><tr><td>5</td><td>戊</td><td>土</td><td>阳</td></tr><tr><td>6</td><td>己</td><td>土</td><td>阴</td></tr><tr><td>7</td><td>庚</td><td>金</td><td>阳</td></tr><tr><td>8</td><td>辛</td><td>金</td><td>阴</td></tr><tr><td>9</td><td>壬</td><td>水</td><td>阳</td></tr><tr><td>10</td><td>癸</td><td>水</td><td>阴</td></tr></tbody></table><h2 id="地支-·-十二个符号" tabindex="-1">地支 · 十二个符号 <a class="header-anchor" href="#地支-·-十二个符号" aria-label="Permalink to &quot;地支 · 十二个符号&quot;">​</a></h2><p>地支共 <strong>12个</strong>，分别对应生肖、时辰、月份、五行与阴阳。</p><table tabindex="0"><thead><tr><th>序号</th><th>地支</th><th>生肖</th><th>时辰</th><th>月份</th><th>五行</th><th>阴阳</th></tr></thead><tbody><tr><td>1</td><td>子</td><td>鼠</td><td>23:00–01:00</td><td>十一月</td><td>水</td><td>阳</td></tr><tr><td>2</td><td>丑</td><td>牛</td><td>01:00–03:00</td><td>十二月</td><td>土</td><td>阴</td></tr><tr><td>3</td><td>寅</td><td>虎</td><td>03:00–05:00</td><td>正月</td><td>木</td><td>阳</td></tr><tr><td>4</td><td>卯</td><td>兔</td><td>05:00–07:00</td><td>二月</td><td>木</td><td>阴</td></tr><tr><td>5</td><td>辰</td><td>龙</td><td>07:00–09:00</td><td>三月</td><td>土</td><td>阳</td></tr><tr><td>6</td><td>巳</td><td>蛇</td><td>09:00–11:00</td><td>四月</td><td>火</td><td>阴</td></tr><tr><td>7</td><td>午</td><td>马</td><td>11:00–13:00</td><td>五月</td><td>火</td><td>阳</td></tr><tr><td>8</td><td>未</td><td>羊</td><td>13:00–15:00</td><td>六月</td><td>土</td><td>阴</td></tr><tr><td>9</td><td>申</td><td>猴</td><td>15:00–17:00</td><td>七月</td><td>金</td><td>阳</td></tr><tr><td>10</td><td>酉</td><td>鸡</td><td>17:00–19:00</td><td>八月</td><td>金</td><td>阴</td></tr><tr><td>11</td><td>戌</td><td>狗</td><td>19:00–21:00</td><td>九月</td><td>土</td><td>阳</td></tr><tr><td>12</td><td>亥</td><td>猪</td><td>21:00–23:00</td><td>十月</td><td>水</td><td>阴</td></tr></tbody></table><h2 id="干支相配-·-六十甲子" tabindex="-1">干支相配 · 六十甲子 <a class="header-anchor" href="#干支相配-·-六十甲子" aria-label="Permalink to &quot;干支相配 · 六十甲子&quot;">​</a></h2><p>天干（10）× 地支（12），<strong>阳干配阳支、阴干配阴支</strong>，共组合出 <strong>60对</strong>，称为「六十甲子」。最小公倍数 LCM(10, 12) = 60。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>甲子 乙丑 丙寅 丁卯 戊辰 己巳 庚午 辛未 壬申 癸酉</span></span>
<span class="line"><span>甲戌 乙亥 丙子 丁丑 戊寅 己卯 庚辰 辛巳 壬午 癸未</span></span>
<span class="line"><span>甲申 乙酉 丙戌 丁亥 戊子 己丑 庚寅 辛卯 壬辰 癸巳</span></span>
<span class="line"><span>甲午 乙未 丙申 丁酉 戊戌 己亥 庚子 辛丑 壬寅 癸卯</span></span>
<span class="line"><span>甲辰 乙巳 丙午 丁未 戊申 己酉 庚戌 辛亥 壬子 癸丑</span></span>
<span class="line"><span>甲寅 乙卯 丙辰 丁巳 戊午 己未 庚申 辛酉 壬戌 癸亥</span></span></code></pre></div><p>60年一轮回，即「一甲子」。2024年为甲辰年（龙年），2025年为乙巳年（蛇年），2026年为丙午年（马年）。</p><h2 id="四大应用维度" tabindex="-1">四大应用维度 <a class="header-anchor" href="#四大应用维度" aria-label="Permalink to &quot;四大应用维度&quot;">​</a></h2><h3 id="纪年" tabindex="-1">纪年 <a class="header-anchor" href="#纪年" aria-label="Permalink to &quot;纪年&quot;">​</a></h3><p>每年对应一个干支，60年循环一次。历史重大事件常以干支命名：「甲午战争」「戊戌变法」「辛亥革命」。</p><h3 id="纪月" tabindex="-1">纪月 <a class="header-anchor" href="#纪月" aria-label="Permalink to &quot;纪月&quot;">​</a></h3><p>每月对应一个地支（固定），天干随年份推算。寅月 = 正月（农历一月），为一年之始。</p><h3 id="纪日" tabindex="-1">纪日 <a class="header-anchor" href="#纪日" aria-label="Permalink to &quot;纪日&quot;">​</a></h3><p>干支纪日是世界上<strong>连续使用时间最长</strong>的纪日法，从未间断，至今已超过 2700 年。</p><h3 id="纪时" tabindex="-1">纪时 <a class="header-anchor" href="#纪时" aria-label="Permalink to &quot;纪时&quot;">​</a></h3><p>一天 24 小时 = 12 个时辰，每个时辰对应一个地支，再配天干推算。</p><h2 id="与其他系统的关联" tabindex="-1">与其他系统的关联 <a class="header-anchor" href="#与其他系统的关联" aria-label="Permalink to &quot;与其他系统的关联&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>天干地支</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── × 五行  →  甲乙木、丙丁火、戊己土、庚辛金、壬癸水（万物属性归类）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── × 阴阳  →  奇阳偶阴，刚柔相济</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── → 十二生肖   子鼠、丑牛……（地支的民俗化）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── → 十二时辰   子时、丑时……（地支的时间化）</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └── → 命理八字   生辰四柱，年月日时各一干支（干支系统最深层的应用）</span></span></code></pre></div><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>说明</th></tr></thead><tbody><tr><td>🌾 农耕</td><td>指导农时，「甲子年」「寅月播种」等</td></tr><tr><td>📜 历史</td><td>重大事件以干支命名</td></tr><tr><td>🏥 中医</td><td>五运六气，以干支推算气候与疾病规律</td></tr><tr><td>🔮 命理</td><td>生辰八字，四柱推命的核心工具</td></tr><tr><td>🏛️ 建筑</td><td>风水方位，以地支对应十二方位</td></tr></tbody></table><h2 id="一句话总结各层关系" tabindex="-1">一句话总结各层关系 <a class="header-anchor" href="#一句话总结各层关系" aria-label="Permalink to &quot;一句话总结各层关系&quot;">​</a></h2><blockquote><p><strong>天干地支</strong>是底层操作系统； <strong>五行阴阳</strong>是它的运算逻辑； <strong>十二生肖</strong>是它的民俗界面； <strong>十二时辰</strong>是它的时间刻度； <strong>八字命理</strong>是它最复杂的应用程序。</p></blockquote>`,27)])])}const u=d(e,[["render",r]]);export{b as __pageData,u as default};
